const PROCESSING_FEE = 5;
const INITIAL_ASSESSMENT_MULTIPLIER = 1.1;
const ALIKE_BUNDLE_DISCOUNT = 15;

function ceilToWholeGold(amount: number): number {
  return Math.ceil(Math.round(amount * 1e6) / 1e6);
}

export function quote(input: { items: Array<{ type: string }> }): number {
  let itemsTotal = input.items.reduce((sum, item) => sum + (BASE_PREMIUMS[item.type] ?? 0), 0);
  const runeCount = input.items.filter((item) => item.type === "rune").length;
  if (runeCount === 3) {
    itemsTotal -= ALIKE_BUNDLE_DISCOUNT;
  }
  const total = itemsTotal * INITIAL_ASSESSMENT_MULTIPLIER + PROCESSING_FEE;
  return ceilToWholeGold(total);
}
